example.code:
class LocalWhisper:
    def __init__(self, model_size: str = "base", device: str = None):
        if device is None:
            device = "cuda" if torch.cuda.is_available() else "cpu"
        self.model = whisper.load_model(model_size, device=device)

    def transcribe(self, audio_path: str, language: str = None,
                   task: str = "transcribe", word_timestamps: bool = False) -> dict:
        result = self.model.transcribe(audio_path, language=language,
                                       task=task, word_timestamps=word_timestamps)
        return {"text": result["text"], "segments": result["segments"],
                "language": result["language"]}

class FasterWhisperTranscriber:
    def transcribe(self, audio_path: str, language: str = None,
                   beam_size: int = 5, vad_filter: bool = True) -> dict:
        segments, info = self.model.transcribe(
            audio_path, language=language, beam_size=beam_size,
            word_timestamps=True, vad_filter=vad_filter
        )
        full_text = ""
        all_segments = []
        for segment in segments:
            all_segments.append({
                "start": segment.start, "end": segment.end, "text": segment.text
            })
            full_text += segment.text
        return {"text": full_text.strip(), "segments": all_segments,
                "language": info.language, "duration": info.duration}

